  ],
  "proposed_actions": [
    {
      "kind": "ghost_completion",
      "title": "建议连接 Heater 出口至 Flash 入口",
      "target": "heater-3.outlet -> flash-15.inlet",
      "rationale": "Heater 出口附近存在高对齐的 Flash Drum 入口（对齐分 0.94）, 且符合常见的进料-加热-闪蒸拓扑。虽然候选刚被关闭，但连接仍符合流程约束。",
      "patch": {
        "op": "connect",
        "from": { "unit_id": "heater-3", "port": "outlet" },
        "to": { "unit_id": "flash-15", "port": "inlet" },
        "stream": { "name": "H-602", "auto_route": true }
